<?php namespace App\Filament\Resources\PayrollResource\Pages;use App\Filament\Resources\PayrollResource;use Filament\Actions;use Filament\Resources\Pages\EditRecord;class EditPayroll extends EditRecord{    protected static string $resource = PayrollResource::class;    protected function getHeaderActions(): array    {        return [            Actions\DeleteAction::make(),        ];    }    protected function mutateFormDataBeforeSave(array $data): array    {        $data['net_salary'] = $this->calculateNetSalary($data);        return $data;    }    private function calculateNetSalary(array $data): float    {        $basic = (float) ($data['basic_salary'] ?? 0);        $allowances = collect($data['allowances'] ?? [])->sum('amount');        $deductions = collect($data['deductions'] ?? [])->sum('amount');        $loan = (float) ($data['loan_deduction'] ?? 0);        $tax = (float) ($data['tax_deduction'] ?? 0);        return max(0, $basic + $allowances - $deductions - $loan - $tax);    }}